UPDATE content_settings SET 
  title_id = 'Kebijakan Pengembalian & Penukaran',
  title_en = 'Return & Exchange Policy',
  content_id = '<h2>Kebijakan Pengembalian</h2><p>Kami menerima pengembalian dan penukaran produk dalam waktu <strong>7 hari</strong> setelah barang diterima, dengan syarat:</p><ul><li>Produk belum pernah digunakan atau dicuci</li><li>Label dan tag masih terpasang</li><li>Menyertakan bukti pembelian (nomor order)</li><li>Produk dalam kondisi asli dan kemasan yang baik</li></ul><h2>Cara Pengembalian</h2><ol><li>Hubungi customer service kami melalui halaman <strong>Kontak</strong></li><li>Sertakan nomor order dan alasan pengembalian</li><li>Tim kami akan memverifikasi permintaan dalam 1-2 hari kerja</li><li>Kirim barang ke alamat yang diberikan oleh tim kami</li><li>Setelah barang diterima dan diverifikasi, refund akan diproses dalam 3-5 hari kerja</li></ol><h2>Produk yang Tidak Dapat Dikembalikan</h2><ul><li>Produk yang sudah dicuci atau dipakai</li><li>Produk dengan label yang sudah dilepas</li><li>Produk sale/diskon tidak dapat dikembalikan</li></ul><h2>Penukaran</h2><p>Penukaran ukuran dapat dilakukan dengan menghubungi customer service kami. Biaya pengiriman penukaran ditanggung oleh pembeli.</p>',
  content_en = '<h2>Return Policy</h2><p>We accept returns and exchanges within <strong>7 days</strong> of receiving your order, subject to the following conditions:</p><ul><li>Product must be unworn and unwashed</li><li>Original tags and labels must be attached</li><li>Proof of purchase (order number) is required</li><li>Product must be in original condition and packaging</li></ul><h2>How to Return</h2><ol><li>Contact our customer service through the <strong>Contact</strong> page</li><li>Provide your order number and reason for return</li><li>Our team will verify the request within 1-2 business days</li><li>Ship the item to the address provided by our team</li><li>Once received and verified, refund will be processed within 3-5 business days</li></ol><h2>Non-Returnable Items</h2><ul><li>Products that have been washed or worn</li><li>Products with removed tags</li><li>Sale/discounted items are non-returnable</li></ul><h2>Exchanges</h2><p>Size exchanges can be arranged by contacting our customer service. Shipping costs for exchanges are borne by the buyer.</p>'
WHERE section_key = 'returns';
